use actix_files::Files;
use actix_web::{web, App, HttpServer, HttpResponse, Responder};
use std::path::Path;

async fn file_handler(info: web::Path<String>) -> impl Responder {
    let filename = info.into_inner();
    let path = Path::new("uploads").join(&filename);
    
    if path.exists() && !path.is_dir() {
        Files::new("/", "uploads").index_file(filename).to_response(&path, &mut Vec::new())
    } else {
        HttpResponse::NotFound().body(format!("File not found: {}", filename))
    }
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    HttpServer::new(|| {
        App::new()
            .route("/{filename}", web::get().to(file_handler))
    })
    .bind("127.0.0.1:8080")?
    .run()
    .await
}